mapper.select:
SELECT 
FROM attendance_records ar
         LEFT JOIN employees e ON e.id = ar.user_id
WHERE ar.user_id = #{userId}
  AND ar.deleted_at IS NULL

    AND ar.date >= #{startDate}


    AND ar.date <= #{endDate}


    AND ar.status = #{status}

ORDER BY ar.date DESC, ar.id DESC

SELECT 
FROM attendance_records ar
         LEFT JOIN employees e ON e.id = ar.user_id
WHERE ar.deleted_at IS NULL

    AND ar.user_id = #{userId}


    AND e.department = #{department}


    AND ar.date >= #{startDate}


    AND ar.date <= #{endDate}


    AND ar.status = #{status}

ORDER BY ar.date DESC, ar.id DESC

SELECT FROM attendance_records ar LEFT JOIN employees e ON e.id = ar.user_id WHERE ar.deleted_at IS NULL AND ar.date BETWEEN #{startDate} AND #{endDate}
AND e.department = #{department}
ORDER BY e.department ASC, e.name ASC, ar.date ASC
